// Join game IDs into comma-separated string
const items = $input.all();
const ids = items.map(i => i.json.game_id);
const os = items[0]?.json.os || '';

return {
  json: {
    ids_string: ids.join(','),
    os: os,
    batch_size: ids.length
  }
};

// Split apps array into individual items
const apps = $json.apps || [];
return apps.map(app => ({ json: { ...app } }));

// Map SQL results back to original app objects
const filteredIds = new Set($input.all().map(i => String(i.json.game_id)));
const originalApps = $('Split Apps').all();
return originalApps.filter(a => filteredIds.has(String(a.json.app_id)));

// Prepare input for sub-workflows
const apps = $input.all().map(i => i.json);
const os = $('Join IDs').first().json.os;

return [{
  json: {
    data: { apps: apps },
    os: os
  }
}];
